prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?participant) AS ?participantCount)
       (SAMPLE(?participantName) AS ?exampleParticipantName)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0ba102e82f484407a4dbcb9bcafdd920" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo .
  OPTIONAL { ?participant bbo:name ?participantName . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?participant) AS ?participantCount)
  (SAMPLE(?participantName) AS ?exampleParticipantName)
  (SAMPLE(?containerType) AS ?containerTypeExample)
WHERE {
  ?model a bboExt:Model .
  {
    ?model tai:normalizedId "0ba102e82f484407a4dbcb9bcafdd920" .
  }
  UNION
  {
    ?model tai:originalId "0ba102e82f484407a4dbcb9bcafdd920" .
  }

  ?defs tai:belongsTo ?model .

  {
    ?container a bboExt:Choreography .
    ?container tai:belongsTo ?defs .
  }
  UNION
  {
    ?container a bboExt:Collaboration .
    ?container tai:belongsTo ?defs .
  }

  ?participant a bboExt:Participant ;
               tai:belongsTo ?container .
  OPTIONAL { ?participant bbo:name ?participantName . }

  BIND (IF(EXISTS{?container a bboExt:Choreography}, "Choreography", "Collaboration") AS ?containerType)
}
